C pseudo2d.fC PSEUDO-SPECTRAL CALCULATION  -2D-C              CODED BY DR T. FURUMURA (HOKKAIDO UNIV. OF EDUCATION)C THIS CODE MUST BE LINKED WITH FFTFORT.F.C             (COMMENTED BY H. TAKENAKA ON 17 AUGUST 1992)C***********************************************************************C  PARAMETER                                                           *C***********************************************************************      PARAMETER ( ZERO = 0.0 , TRUE = 1   , FALSE = 0   )               C  NUMBER OF MESH GRIDS*      PARAMETER ( NX = 256, NY = 256, NY2 = NY*2 )        PARAMETER ( NX = 64, NY = 64, NY2 = NY*2 )  C  MESH SIZE(m) AND INTERVAL OF TIME STEP(msecs)      PARAMETER ( DX = 1.5, DY = 1.5, DT = 0.005)  *      PARAMETER ( NTMAX = 1301  , NWRITE =   50  )       PARAMETER ( NTMAX = 100  , NWRITE =   11  ) *      PARAMETER ( NSKIP = NTMAX/2, REDUCE = 8.0 ,NTSKP=NTMAX/NSKIP+1 )        PARAMETER ( NSKIP = 1, REDUCE = 8.0 ,NTSKP=NTMAX/NSKIP+1 )  C  SOURCE VOLUME AND SOURCE TIME FUNCTION (HERRMANN'S FUNCTION)      PARAMETER ( AX = DX    , AY = DY    , AT = 0.50   , T0 = AT*2  )*      PARAMETER ( alpha=1500.0,T0=0.15,lambda=1.0)    C  SOURCE POSITION      PARAMETER ( I0 =Nx/2, J0 = Ny/2)                                    C  SOURCE MECHANISM (MOMENT TENSOR AND SINGLE FORCES)      PARAMETER ( RXX= 0.0, RXZ = 1.0, RZZ = 0.0, RFX = 0.0, RFZ = 0.0) C  NUMBER OF OBSERVATION POINTS FOR SEISMIC TRACES*      PARAMETER ( NST = 55                              )       PARAMETER ( NST = 1                              )               C      PARAMETER ( NXA =  20  , NYA =  20                )              C***********************************************************************C  DIMENSION                                                           *C***********************************************************************      REAL     SXX  (NX,NY) ,  SXY  (NX,NY)  ,   SYY  (NX,NY)                 REAL     EXX  (NX,NY) ,  EXY  (NX,NY)  ,   EYY  (NX,NY)           *      EQUIVALENCE   ( SXX, EXX ), ( SYY, EYY ), ( SXY, EXY )                  REAL     DEN  (NX,NY) ,  RIG  (NX,NY)  ,   LAM  (NX,NY)                 REAL     UX   (NX,NY) ,  UY   (NX,NY)                                   REAL     UP   (NX,NY) ,  US   (NX,NY)                                   REAL     DXUX (NX,NY) ,  DXUY (NX,NY)                                   REAL     DYUX (NX,NY) ,  DYUY (NX,NY)                                   REAL     UXT1 (NX,NY) ,  UYT1 (NX,NY)                                   REAL     DXSXX(NX,NY) ,  DXSXY(NX,NY)                                   REAL     DYSXY(NX,NY) ,  DYSYY(NX,NY)                                   INTEGER  IMAP (NX,NY )                                            *      EQUIVALENCE   ( SXX, DXSXX ), ( SYY, DYSYY )                            REAL     GGG  (NX,NY)                                                   REAL     CYWORK(NY2)   ,  CXWORK( NX )                                  REAL     UXALL  ( NST,NTSKP ) , UYALL  ( NST,NTSKP )                    REAL     UPALL  ( NST,NTSKP ) , USALL  ( NST,NTSKP )                    INTEGER  ISTX( NST )  , ISTY( NST )                                     REAL     SOX ( NST )  , SOY ( NST )                                     REAL     GX  ( NX )   , GY  ( NY )  	real tarray(2)                              *      CHARACTER*12 PTIME                                                *      CHARACTER*8  PDATE *	character*24   fdate                                               C********************************************************************** C   OUTPUT FILE NAME                                                  * C**********************************************************************       CHARACTER*20   ONAME, WNAME, PNAME                                      CHARACTER*80   TITLE                                                    INTEGER*4      ISPOUT ( 4 ) , ISPWAV ( 4 )                        C  NAMES OF FILES*      PNAME = 'SLAB2.PARM'                                              *      WNAME = 'FORSLAB9.WAV'                                                  ONAME = 'snap.out'                                              C  OBSERVATION POINTS FOR TRACES      DO 77  I = 1, NST                                                 *        ISTX ( I ) = 20 + (I-1) * 4                                             ISTX ( I ) = 4+(I-1) * 2                                             ISTY ( I ) =  1                                                   77  CONTINUE                                                          C  INPUT PARAMETERSC     READING STRUCTURAL MODEL*      type*,'entering modelin'      call modelin(nx,ny,rig,lam,den)*      type*,'leaving modelin'                                                                                                                       C********************************************************************** C     INITIAL CONDITION                                               * C********************************************************************** C                                                                       C     CALL DATE ( PDATE ) *      write(*,*) fdate()                                                    C     CALL CLOCK( PTIME,1 )                                             C                                                                             KX = NBEGI2( NX )                                                       KY = NBEGI2( NY )                                                 C COORDINATES OF OBSERVATION POINTS      DO 51 I = 1, NST                                                          SOX( I ) = ( ISTX(I) - 1 ) * DX                                         SOY( I ) = ( ISTY(I) - 1 ) * DY                                   51  CONTINUE                                                          C COORDINATE OF SOURCE LOCATION      STX = (I0-1)*DX                                                         STY = (J0-1)*DY                                                   C COORDINATES OF MESH GRID POINTS      DO 52 I = 1, NX                                                           GX ( I ) = ( I - 1 ) * DX                                         52  CONTINUE                                                                DO 53 J = 1, NY                                                           GY ( J ) = ( J - 1 ) * DY                                         53  CONTINUE                                                          C     TIME WHEN SOURCE TIME FUNCTION (HERRMANN'S FUNCTION)C     REDUCES TO ZERO AGAIN      FTMAX = T0 + AT*2                                                 C  INITIALIZE DISPLACEMENT FIELD & ITS TEMPORAL DERIVATIVE TO ZERO                                                                CALL   CLEAR ( UXT1  , NX, NY, ZERO )                                   CALL   CLEAR ( UYT1  , NX, NY, ZERO )                                   CALL   CLEAR ( UX    , NX, NY, ZERO )                                   CALL   CLEAR ( UY    , NX, NY, ZERO )      	  	  do ist=1,NST	  do it=1,ntskp	  UXALL  (ist,it)=0.0	  UPALL  (ist,it)=0.0	  UYALL  (ist,it)=0.0	  USALL  (ist,it)=0.0	  enddo	  enddo                                                                              OPEN( 16, FILE=ONAME,     FORM = 'FORMATTED', STATUS='unknown',          &      ACCESS='SEQUENTIAL',IOSTAT=IER )                  IF( IER.NE.0 ) THEN                                                         WRITE ( 6,* ) ' FILE(16) CREATE ERR', IER                               STOP                                                                END IF                                                            C                                                                       C********************************************************************** C       ABSORBING  BOUNDARY CONDITION                                 * C**********************************************************************       APARA = 0.015                                                           DO 209  I = 1,NX                                                        DO 209  J = 1,NY                                                           IF( I .LT. NXA ) THEN                                                     GG = EXP( -( ( APARA * (NXA-I     ) )**2 ) )                          ELSE IF ( I .GT. ( NX-NXA+1 ) ) THEN                                      GG = EXP( -( ( APARA * (I-NX+NXA-1) )**2 ) )                          ELSE IF ( J .GT. ( NY-NYA+1 ) ) THEN                                      GG = EXP( -( ( APARA * (J-NY+NYA-1) )**2 ) ) *         elseif (j .lt. nya) then !top boundary damper*           GG = EXP( -( ( APARA * (NyA-j     ) )**2 ) )         ELSE                                                                      GG = 1.0                                                              END IF                                                                  GGG ( I,J ) = GG  *		 type*,'i,j,GG=',i,j,GG 209  CONTINUE                                                          C                                                                       C***********************************************************************C  TIME STEP START                                                     *C***********************************************************************C                                                                             NTW = 0       NTT = 0                                              C                                                                             DO  800  IT = 1, NTMAX                                            C                                                                             NTT = NTT + 1                                                           T     =   DT * (IT-1)                                                   NTW   =   NTW + 1                                                 C                                                                             CALL   DIFFX  ( UX, DXUX, CXWORK, NX, NY, KX, DX )                      CALL   DIFFX  ( UY, DXUY, CXWORK, NX, NY, KX, DX ) *      CALL   DIFFx ( UX, DYUX, CYWORK, NX, NY, KY, DY )           *      CALL   DIFFx ( UY, DYUY, CYWORK, NX, NY, KY, DY )                     CALL   DIFFYU ( UX, DYUX, CYWORK, NX, NY, KY, DY, NY2 )                 CALL   DIFFYU ( UY, DYUY, CYWORK, NX, NY, KY, DY, NY2 )           C                                                                             DO 4 I = 1,NX                                                           DO 4 J = 1,NY                                                              EXX ( I,J ) =   DXUX ( I,J )                                            EYY ( I,J ) =   DYUY ( I,J )                                            EXY ( I,J ) = ( DXUY ( I,J ) + DYUX ( I,J ) ) / 2.0  *		 type*,'i,j,EXX(i,j)=',i,j,EXX(i,j)*		 type*,'i,j,EYY(i,j)=',i,j,EYY(i,j) 4    CONTINUE                                                                                                                                        IF ( NTT .EQ. NSKIP ) THEN                                               DO 25 NS = 1,NST                                                           NTT = 0                                                                 ISX  =  ISTX ( NS )                                                     ISY  =  ISTY ( NS )                                                     IT1  =  IT / NSKIP + 1                                                  UXALL ( NS,IT1 ) =   UX   ( ISX,ISY )                                   UYALL ( NS,IT1 ) =   UY   ( ISX,ISY ) 		  type*,'NS,IT1,UXALL ( NS,IT1 )=',NS,IT1,UXALL ( NS,IT1 )          UPALL ( NS,IT1 ) = ( DXUX ( ISX,ISY ) + DYUY ( ISX,ISY ) )              USALL ( NS,IT1 ) = ( DYUX ( ISX,ISY ) - DXUY ( ISX,ISY ) )      25  CONTINUE                                                                END IF                                                                                                                                          DO 5 I = 1,NX                                                           DO 5 J = 1,NY                                                              RAM1  = LAM ( I,J )                                                     RIG1  = RIG ( I,J ) * 2.0          EXXIJ = EXX ( I,J )                                                     EXYIJ = EXY ( I,J )                                                     EYYIJ = EYY ( I,J )                                                     SXX ( I,J )  = ( RAM1+RIG1 ) * EXXIJ  +  RAM1 * EYYIJ                   SYY ( I,J )  = ( RAM1+RIG1 ) * EYYIJ  +  RAM1 * EXXIJ                   SXY ( I,J )  =   RIG1 * EXYIJ                                     5  CONTINUE                                                        C                                                                             CALL   DIFFX  ( SXX, DXSXX, CXWORK, NX, NY, KX, DX )  *	  Do i=1,Nx*	    Do j=1,Ny*		  type*,'i,j,SXX, DXSXX=',i,j,SXX(i,j), DXSXX(i,j)*		Enddo*	  Enddo*	  pause      CALL   DIFFX  ( SXY, DXSXY, CXWORK, NX, NY, KX, DX )       CALL   DIFFYS ( SXY, DYSXY, CYWORK, NX, NY, KY, DY, NY2 )               CALL   DIFFYS ( SYY, DYSYY, CYWORK, NX, NY, KY, DY, NY2 )                      C *      call r1(amp,T)  !set source timefunction *      type*,' t,amp=',t,amp                                                                                                                                   DO 7 I =  1, NX                                                         DO 7 J =  1, NY                                                   C                                                                                GG   = GGG ( I,J )                                                      DEN1 = DEN ( I,J )                                             C *        set the body force term                                                                               FX1 =  ZERO                                                             FY1 =  ZERO                                                             IF ( T .LE. FTMAX )   THEN                                                FX1 = FX1                                                         &      + RXX * FXMXX ( I, J, I0, J0, DX, DY, AX, AY, T, T0, AT )        &      + RXZ * FXMXZ ( I, J, I0, J0, DX, DY, AX, AY, T, T0, AT )        &      + RFX * FX    ( I, J, I0, J0, DX, DY, AX, AY, T, T0, AT )              FY1 = FY1                                                         &      + RZZ * FZMZZ ( I, J, I0, J0, DX, DY, AX, AY, T, T0, AT )        &      + RXZ * FZMXZ ( I, J, I0, J0, DX, DY, AX, AY, T, T0, AT )        &      + RFZ * FZ    ( I, J, I0, J0, DX, DY, AX, AY, T, T0, AT )            END IF *	  dj=(float(i-isx)**2+float(j-isz)**2)*lambda*	  FX1=amp*(float(i-I0))*exp(-dj)*	  FY1=amp*(float(j-J0))*exp(-dj)*		 type*,'i,j,Fx1,Fy1=',i,j,Fx1,Fy1                                                                                      UXT2IJ  = ( DXSXX (I,J) + DYSXY ( I,J ) + FX1 ) / DEN1                  UYT2IJ  = ( DXSXY (I,J) + DYSYY ( I,J ) + FY1 ) / DEN1         *		 type*,'DXSXX (I,J),DYSXY ( I,J )=',i,j,DXSXX (I,J),DYSXY ( I,J )                                                                                 UXT1 ( I,J ) =  UXT1 ( I,J ) * GG + DT * UXT2IJ                         UYT1 ( I,J ) =  UYT1 ( I,J ) * GG + DT * UYT2IJ                                                                                                 UX   ( I,J ) =  UX   ( I,J ) * GG + DT * UXT1( I,J )                    UY   ( I,J ) =  UY   ( I,J ) * GG + DT * UYT1( I,J )  *		 type*,'UXT1(i,j)=',i,j,UXT1(i,j)                                                                                 UP   ( I,J ) =  DXUX ( I,J ) + DYUY ( I,J )                             US   ( I,J ) =  DXUY ( I,J ) - DYUX ( I,J )                                                                                              7   CONTINUE  *      dump*      pauseC                                                                       C***********************************************************************C  WRITE  SNAP SHOT                                                    *C***********************************************************************C                                                                             IF( mod(it,Nwrite) .EQ. 0 ) THEN                                        *        NTW = ZERO       write(16,2100) T 2100 format(e10.3)      do 777 iy=1,ny         write(16,2400) (UP(ix,iy),ix=1,nx)  777 continue      do 999 iy=1,ny         write(16,2400) (US(ix,iy),ix=1,nx)  999 continue 2400 format(10e10.3)                                                     *        WRITE( 16 )  T                                                  *        WRITE( 16 )  UP, US                                                   END IF                                                            C                                                                       C***********************************************************************C  NEXT TIME STEP                                                      *C***********************************************************************C  	type*,'passed time step',it*	Pause 'passed time step'  800 CONTINUE                                                          C                                                                       C***********************************************************************C  WRITE  WAVEFORM                                                      C***********************************************************************C                                                                       *      WRITE( 26 ) UPALL,    USALL,                                      *     &            UXALL ,   UYALL                                       C                                                                             CLOSE( 16 )                                                       *      CLOSE( 26 )                                                       C                    *	write(*,*) fdate(),etime(tarray)                                                                                              STOP                                                                    END                                                               C                                                                       C***********************************************************************C  ***********   END OF MAIN PROGRAM  *****************                *C***********************************************************************C                                                                       **	First deivative of a Gaussian function*	  subroutine r1(f,t)      parameter (t0=.15,alpha=25.1327,rtpi=1.77245)	  alp1=alpha*alpha*(t-t0)*(t-t0)	  ep=exp(-alp1)	  f=0.5*alpha*(1.-2.*alp1)*ep/rtPi	  return	  end	  subroutine modelin(nx,ny,rig,lam,den)	  real rig(nx,ny),lam(nx,ny),den(nx,ny)      real alpha0,beta0,alpha1,beta1	  data  alpha0,alpha1,beta0,beta1/2.7,4.4,1.5,2.2/	  ilx=3*nx/8	  iux=nx/2	  ily=3*ny/8	  iuy=ny/2	  	  do ix=1,nx	  do iy=1,ny	  if (((ix .le. iux).and.(ix .ge. ilx)).and.((iy .le. iuy).and.     &          (iy .ge. ily))) then	    rig(ix,iy)=beta1*beta1	    lam(ix,iy)=2.0*alpha1*alpha1-rig(ix,iy)	    den(ix,iy)=1.0	  else	    rig(ix,iy)=beta0*beta0	    lam(ix,iy)=2.0*alpha0*alpha0-rig(ix,iy)	    den(ix,iy)=1.0	  endif	  enddo	  enddo  		  return	  end      REAL FUNCTION  FXMXZ ( I, J, I0, J0, DX, DZ, AX, AZ, T, T0, AT )        X0 = I0 * DX                                                            Z0 = J0 * DZ                                                            X  = I  * DX                                                            Z  = J  * DZ                                                            FHX =  HERRMAN ( AX, X, X0 )                                            FHZ =-DHERRMAN ( AZ, Z, Z0 )                                            FHT =  HERRMAN ( AT, T, T0 )                                            FXMXZ  = FHX * FHZ * FHT                                                RETURN                                                                  END                                                                                                                                             REAL FUNCTION  FZMXZ ( I, J, I0, J0, DX, DZ, AX, AZ, T, T0, AT )        X0 = I0 * DX                                                            Z0 = J0 * DZ                                                            X  = I  * DX                                                            Z  = J  * DZ                                                            FHX =-DHERRMAN ( AX, X, X0 )                                            FHZ =  HERRMAN ( AZ, Z, Z0 )                                            FHT =  HERRMAN ( AT, T, T0 )                                            FZMXZ  = FHX * FHZ * FHT                                                RETURN                                                                  END                                                                                                                                             REAL FUNCTION  FZMZZ ( I, J, I0, J0, DX, DZ, AX, AZ, T, T0, AT )        X0 = I0 * DX                                                            Z0 = J0 * DZ                                                            X  = I  * DX                                                            Z  = J  * DZ                                                            FHX =  HERRMAN ( AX, X, X0 )                                            FHZ =-DHERRMAN ( AZ, Z, Z0 )                                            FHT =  HERRMAN ( AT, T, T0 )                                            FZMZZ  = FHX * FHZ * FHT                                                RETURN                                                                  END                                                                                                                                             REAL FUNCTION  FXMXX ( I, J, I0, J0, DX, DZ, AX, AZ, T, T0, AT )        X0 = I0 * DX                                                            Z0 = J0 * DZ                                                            X  = I  * DX                                                            Z  = J  * DZ                                                            FHX =-DHERRMAN ( AX, X, X0 )                                            FHZ =  HERRMAN ( AZ, Z, Z0 )                                            FHT =  HERRMAN ( AT, T, T0 )                                            FXMXX   = FHX * FHZ * FHT                                               RETURN                                                                  END                                                                                                                                             REAL FUNCTION  FX ( I, J, I0, J0, DX, DZ, AX, AZ, T, T0, AT )           X0 = I0 * DX                                                            Y0 = J0 * DZ                                                            X  = I  * DX                                                            Z  = J  * DZ                                                            FHX = HERRMAN ( AX, X, X0 )                                             FHZ = HERRMAN ( AZ, Z, Z0 )                                             FHT = HERRMAN ( AT, T, T0 )                                             FX  = FHX * FHZ * FHT                                                   RETURN                                                                  END                                                               C                                                                             REAL FUNCTION  FZ ( I, J, I0, J0, DX, DZ, AX, AZ, T, T0, AT )           X0 = I0 * DX                                                            Z0 = J0 * DZ                                                            X  = I  * DX                                                            Z  = J  * DZ                                                            FHX = HERRMAN ( AX, X, X0 )                                             FHZ = HERRMAN ( AY, Z, Z0 )                                             FHT = HERRMAN ( AT, T, T0 )                                             FZ  = FHX * FHZ * FHT                                                   RETURN                                                                  END                                                               C                                                                             REAL FUNCTION  HERRMAN ( A, X, X0 )                                     A2  = 2.0 * A                                                           T   = X - X0                                                            TD  = ( T + A2 ) / A                                                    IF( T .LE. -A2 ) THEN                                                       HERRMAN  = 0.0                                                          RETURN                                                              ELSE IF( (T .GT. -A2) .AND. (T .LE. -A) ) THEN                              HERRMAN  = ( 0.5 * TD**2 ) / A2                                         RETURN                                                              ELSE IF( (T .GT. -A ) .AND. (T .LE.  A) ) THEN                              HERRMAN  = ( -0.5 * TD**2 + 2.0 * TD - 1.0 ) / A2                       RETURN                                                              ELSE IF( (T .GT.  A ) .AND. (T .LE. A2) ) THEN                              HERRMAN  = (  0.5 * TD**2 - 4.0 * TD + 8.0 ) / A2                       RETURN                                                              ELSE                                                                        HERRMAN  = 0.0                                                          RETURN                                                              END IF                                                                  END                                                               C                                                                             REAL FUNCTION  DHERRMAN ( A, X, X0 )                                    A2  = 2.0 * A                                                           T   = X - X0                                                            TD  = ( T + A2 ) / A                                                    IF( T .LE. -A2 ) THEN                                                       DHERRMAN  = 0.0                                                         RETURN                                                              ELSE IF( (T .GT. -A2) .AND. (T .LE. -A) ) THEN                              DHERRMAN  = (       TD    ) / A2  * 2.0                                 RETURN                                                              ELSE IF( (T .GT. -A ) .AND. (T .LE.  A) ) THEN                              DHERRMAN  = (       -TD    + 2.0            ) / A2  * 2.0               RETURN                                                              ELSE IF( (T .GT.  A ) .AND. (T .LE. A2) ) THEN                              DHERRMAN  = (        TD    - 4.0            ) / A2  * 2.0               RETURN                                                              ELSE                                                                        DHERRMAN  = 0.0                                                         RETURN                                                              END IF                                                                  END                                                               C                                                                       C                                                                             INTEGER  FUNCTION NBEGI2( NX )                                    C     INPUT :  KX = 2**N                                                C     OUTPUT:  N                                                              NXX = NX                                                                KX = 0                                                                  DO 10 I = 1,NX                                                            KX = KX + 1                                                             NXX = NXX/2                                                             IF( NXX.EQ.1 ) GOTO 99                                             10 CONTINUE                                                             99 NBEGI2   =    KX                                                        RETURN                                                                  END                                                               C                                                                             SUBROUTINE   DIFFX ( A, B, WORK, NX, NY, KX, DX )                       REAL         A( NX,NY ) , B( NX,NY ) , WORK ( NX )                C                                                                             DO 100 J = 1, NY                                                                                                                                  DO 1 I = 1,NX                                                              WORK( I )  =  A ( I,J )                                       1      CONTINUE                                                                                                                                        CALL  FFTR ( WORK, KX, ILL )                                                                                                                    DKX = 6.283185 / NX / DX                                                NXD2 = NX / 2                                                                                                                                   WORK (      1  ) = 0.0                                                  WORK ( NXD2+1  ) = 0.0                                                                                                                          DO 2 I = 2, NXD2                                                          WC = -DKX*( I-1 ) * WORK (      I )                                     WS =  DKX*( I-1 ) * WORK ( NXD2+I )                                     WORK (      I ) = WS                                                    WORK ( NXD2+I ) = WC                                           2      CONTINUE                                                                                                                                        CALL  FFTRI ( WORK, KX, ILL )                                                                                                                   DO 3 I = 1,NX                                                             B ( I,J ) =  WORK ( I )                                        3      CONTINUE                                                                                                                                 100  CONTINUE                                                                                                                                        RETURN                                                                  END                                                               C                                                                             SUBROUTINE   DIFFYU ( A, B, WORK, NX, NY, KY, DY, NY2 )           C     DERIVATIVE BY SYMMETRIC DIFFERENTIATION METHOD      REAL         A( NX,NY ) , B( NX,NY )                                    REAL         WORK( NY2 )                                          C                                                                             DO 100 I = 1, NX                                                                                                                                  DO 1 J = 1, NY                                                            WORK ( NY-J+1 ) =  A ( I,J )                                            WORK ( NY+J   ) =  A ( I,J )                                   1      CONTINUE                                                                                                                                        CALL  FFTR ( WORK, KY+1, ILL )                                                                                                                  DKY = 6.283185 / NY2 / DY                                               NYD2 = NY2 / 2                                                                                                                                  WORK (      1  ) = 0.0                                                  WORK ( NYD2+1  ) = 0.0                                                                                                                          DO 2 J = 2, NYD2                                                          WC = -DKY*( J-1 ) * WORK (      J )                                     WS =  DKY*( J-1 ) * WORK ( NYD2+J )                                     WORK (      J ) = WS                                                    WORK ( NYD2+J ) = WC                                           2      CONTINUE                                                                                                                                        CALL  FFTRI ( WORK, KY+1, ILL )                                                                                                                 DO 3 J = 1, NY                                                            B ( I,J ) =  WORK ( NY+J )                                     3      CONTINUE                                                                                                                                 100  CONTINUE                                                                                                                                        RETURN                                                                  END                                                               C                                                                             SUBROUTINE   DIFFYS ( A, B, WORK, NX, NY, KY, DY, NY2 )                 REAL         A( NX,NY ) , B( NX,NY )                                    REAL         WORK( NY2 )                                          C                                                                             DO 100 I = 1, NX                                                                                                                                  DO 1 J = 1, NY                                                            WORK (    J ) =  0.0                                                    WORK ( NY+J ) =  A ( I,J )                                     1      CONTINUE                                                                                                                                *        CALL  FFTR ( WORK, KY+1, INV, ILL ) *CHECK THIS LINE        CALL  FFTR ( WORK, KY+1, ILL )                                                                                                             DKY  = 6.283185 / NY2 / DY                                              NYD2 = NY2 / 2                                                                                                                                  WORK (      1  ) = 0.0                                                  WORK ( NYD2+1  ) = 0.0                                                                                                                          DO 2 J = 2, NYD2                                                          WC = -DKY*( J-1 ) * WORK (      J )                                     WS =  DKY*( J-1 ) * WORK ( NYD2+J )                                     WORK (      J ) = WS                                                    WORK ( NYD2+J ) = WC                                           2      CONTINUE                                                                                                                                        CALL  FFTRI ( WORK, KY+1, ILL )                                                                                                                 DO 3 J = 1, NY                                                            B ( I,J ) = WORK ( NY+J )                                      3      CONTINUE                                                                                                                                 100  CONTINUE                                                                                                                                        RETURN                                                                  END                                                               C                                                                             SUBROUTINE  CLEAR( A, NX, NY, VALUE )                                   REAL   A( NX,NY )                                                       DO 1 I = 1,NX                                                           DO 1 J = 1,NY                                                                A( I,J ) = VALUE                                              1    CONTINUE                                                                RETURN                                                                  END                                                               C                                                                             SUBROUTINE  CLEAR3( E, NX, NY, NK, VALUE )                              REAL   E( NX, NY ,NK )                                                  DO 1 I = 1,NX                                                           DO 1 J = 1,NY                                                           DO 1 K = 1,NK                                                                E( I,J,K) = VALUE                                             1    CONTINUE                                                                RETURN                                                                  END                                                               C                                                                             SUBROUTINE PADD ( A, NX, NY, NX0 ,NX1, NY0, NY1, VALUE )                REAL A( NX,NY )                                                         DO 1 I = NX0 , NX1                                                      DO 1 J = NY0 , NY1                                                           A( I,J ) = VALUE                                               1   CONTINUE                                                                RETURN                                                                  END                                                               C  fftfort.fC=====================================================================C         C     SUBROUTINE FFTC PERFORMS DISCRETE FOURIER TRANSFORM BY          C         C     RADIX-4 COMPLEX FFT ALGORITHM                                   C         C     USAGE: CALL FFTC(A,M,INV,ILL)                                   C         C          A......1-DIMENSIONAL COMPLEX ARRAY OF SIZE 2**M            C         C                 INPUT....DATA TO BE TRANSORMED                      C         C                 OUTPUT...TRANSFORMED DATA                           C         C          M......INTEGER INPUT...BASE 2 LOGARITHM OF DATA SIZE       C         C          INV....INTEGER INPUT...0: FORWAED TRANSFORMATION           C         C                              ...1: INVERSE TRANSFORMATION           C         C                 (DIVIDE BY N=2**M TO OBTAIN THE TRUE INVERSE)       C         C          ILL....INTEGER OUTPUT..ERROR CODE 0: NORMAL TERMINATION    C         C                                            30000: PARAMETER ERROR   C         C     SLAVE ROUTINE: BITRVC(NUMPAC) FOR BIT REVERSAL REARRANGEMENT    C         C     AUTHOR: I.NINOMIYA (CHUBU UNIVERSITY,KASUGAI,AICHI JAPAN 487)   C         C     DATA OF CREATION:  1981-04-01                                   C         C=====================================================================C         C---------------------------------------------------------------------C               SUBROUTINE FFTC(A,M,INV,ILL)                                              C---------------------------------------------------------------------C               DOUBLE PRECISION DC,DS,CC,SS,CO,SO,CN,SN,PP                                     DIMENSION A(*),DC(32),DS(32)                                              C---------------------------------------------------------------------C         C     DC(I)=COS(PI/2**(I+1)) DS(I)=SIN(PI/2**(I+1))                             C---------------------------------------------------------------------C               DATA DC( 1)/ 0.707106781186547531D+00/                                          DATA DC( 2)/ 0.923879532511286752D+00/                                          DATA DC( 3)/ 0.980785280403230444D+00/                                          DATA DC( 4)/ 0.995184726672196887D+00/                                          DATA DC( 5)/ 0.998795456205172391D+00/                                          DATA DC( 6)/ 0.999698818696204222D+00/                                          DATA DC( 7)/ 0.999924701839144545D+00/                                          DATA DC( 8)/ 0.999981175282601137D+00/                                          DATA DC( 9)/ 0.999995293809576177D+00/                                          DATA DC(10)/ 0.999998823451701907D+00/                                          DATA DC(11)/ 0.999999705862882213D+00/                                          DATA DC(12)/ 0.999999926465717850D+00/                                          DATA DC(13)/ 0.999999981616429293D+00/                                          DATA DC(14)/ 0.999999995404107320D+00/                                          DATA DC(15)/ 0.999999998851026833D+00/                                          DATA DC(16)/ 0.999999999712756701D+00/                                          DATA DC(17)/ 0.999999999928189179D+00/                                          DATA DC(18)/ 0.999999999982047291D+00/                                          DATA DC(19)/ 0.999999999995511826D+00/                                          DATA DC(20)/ 0.999999999998877953D+00/                                          DATA DC(21)/ 0.999999999999719488D+00/                                          DATA DC(22)/ 0.999999999999929876D+00/                                          DATA DC(23)/ 0.999999999999982472D+00/                                          DATA DC(24)/ 0.999999999999995615D+00/                                          DATA DC(25)/ 0.999999999999998904D+00/                                          DATA DC(26)/ 0.999999999999999722D+00/                                          DATA DC(27)/ 0.999999999999999931D+00/                                          DATA DC(28)/ 0.999999999999999986D+00/                                          DATA DC(29)/ 0.100000000000000000D+01/                                          DATA DC(30)/ 0.100000000000000000D+01/                                          DATA DC(31)/ 0.100000000000000000D+01/                                          DATA DC(32)/ 0.100000000000000000D+01/                                          DATA DS( 1)/ 0.707106781186547531D+00/                                          DATA DS( 2)/ 0.382683432365089768D+00/                                          DATA DS( 3)/ 0.195090322016128262D+00/                                          DATA DS( 4)/ 0.980171403295606036D-01/                                          DATA DS( 5)/ 0.490676743274180141D-01/                                          DATA DS( 6)/ 0.245412285229122881D-01/                                          DATA DS( 7)/ 0.122715382857199263D-01/                                          DATA DS( 8)/ 0.613588464915447527D-02/                                          DATA DS( 9)/ 0.306795676296597625D-02/                                          DATA DS(10)/ 0.153398018628476561D-02/                                          DATA DS(11)/ 0.766990318742704540D-03/                                          DATA DS(12)/ 0.383495187571395563D-03/                                          DATA DS(13)/ 0.191747597310703308D-03/                                          DATA DS(14)/ 0.958737990959773447D-04/                                          DATA DS(15)/ 0.479368996030668847D-04/                                          DATA DS(16)/ 0.239684498084182193D-04/                                          DATA DS(17)/ 0.119842249050697064D-04/                                          DATA DS(18)/ 0.599211245264242774D-05/                                          DATA DS(19)/ 0.299605622633466084D-05/                                          DATA DS(20)/ 0.149802811316901114D-05/                                          DATA DS(21)/ 0.749014056584715715D-06/                                          DATA DS(22)/ 0.374507028292384129D-06/                                          DATA DS(23)/ 0.187253514146195347D-06/                                          DATA DS(24)/ 0.936267570730980836D-07/                                          DATA DS(25)/ 0.468133785365490931D-07/                                          DATA DS(26)/ 0.234066892682745532D-07/                                          DATA DS(27)/ 0.117033446341372770D-07/                                          DATA DS(28)/ 0.585167231706863850D-08/                                          DATA DS(29)/ 0.292583615853431935D-08/                                          DATA DS(30)/ 0.146291807926715968D-08/                                          DATA DS(31)/ 0.731459039633579864D-09/                                          DATA DS(32)/ 0.365729519816789906D-09/                                    C---------------------------------------------------------------------C               IF(M.LT.0) GO TO 70                                                             NN=2**(M+1)                                                                     L=NN                                                                            G=INV+INV-1                                                                     DO 40 I=2,M,2                                                                   L4=L/4                                                                          DO 10 K0=2,NN,L                                                                 K2=K0+L4                                                                        K1=K2+L4                                                                        K3=K1+L4                                                                        T1=A(K0-1)+A(K1-1)                                                              U1=A(K0-1)-A(K1-1)                                                              T2=A(K0)+A(K1)                                                                  U2=A(K0)-A(K1)                                                                  V1=A(K2-1)+A(K3-1)                                                              W2=(A(K2-1)-A(K3-1))*G                                                          V2=A(K2)+A(K3)                                                                  W1=(A(K3)-A(K2))*G                                                              A(K0-1)=T1+V1                                                                   A(K0)=T2+V2                                                                     A(K2-1)=T1-V1                                                                   A(K2)=T2-V2                                                                     A(K1-1)=U1+W1                                                                   A(K1)=U2+W2                                                                     A(K3-1)=U1-W1                                                                10 A(K3)=U2-W2                                                                     IF(L4.LT.4) GO TO 40                                                            CC=DC(M-I)                                                                      SS=DS(M-I)*G                                                                    PP=SS+SS                                                                        CO=1.D0                                                                         SO=0.D0                                                                         DO 30 J=4,L4,2                                                                  C1=CC                                                                           S1=SS                                                                           P=S1+S1                                                                         C2=(C1-S1)*(C1+S1)                                                              S2=C1*P                                                                         C3=C1-P*S2                                                                      S3=P*C2+S1                                                                      DO 20 K0=J,NN,L                                                                 K2=K0+L4                                                                        K1=K2+L4                                                                        K3=K1+L4                                                                        T1=A(K0-1)+A(K1-1)                                                              U1=A(K0-1)-A(K1-1)                                                              T2=A(K0)+A(K1)                                                                  U2=A(K0)-A(K1)                                                                  V1=A(K2-1)+A(K3-1)                                                              W2=(A(K2-1)-A(K3-1))*G                                                          V2=A(K2)+A(K3)                                                                  W1=(A(K3)-A(K2))*G                                                              A(K0-1)=T1+V1                                                                   A(K0)=T2+V2                                                                     TV1=T1-V1                                                                       TV2=T2-V2                                                                       A(K2-1)=TV1*C2-TV2*S2                                                           A(K2)=TV1*S2+TV2*C2                                                             UW1=U1+W1                                                                       UW2=U2+W2                                                                       A(K1-1)=UW1*C1-UW2*S1                                                           A(K1)=UW1*S1+UW2*C1                                                             UW1=U1-W1                                                                       UW2=U2-W2                                                                       A(K3-1)=UW1*C3-UW2*S3                                                        20 A(K3)=UW1*S3+UW2*C3                                                             CN=CO-PP*SS                                                                     SN=PP*CC+SO                                                                     CO=CC                                                                           CC=CN                                                                           SO=SS                                                                        30 SS=SN                                                                        40 L=L4                                                                            IF(L.EQ.2) GO TO 60                                                             DO 50 K0=2,NN,4                                                                 T1=A(K0-1)                                                                      T2=A(K0)                                                                        A(K0-1)=T1+A(K0+1)                                                              A(K0)=T2+A(K0+2)                                                                A(K0+1)=T1-A(K0+1)                                                           50 A(K0+2)=T2-A(K0+2)                                                        C-------- CALL BIT REVERSAL SUBROUTINE -------------------------------C            60 CALL BITRVC(A,M,ILL)                                                            RETURN                                                                    C-------- ERROR HANDLING ---------------------------------------------C            70 ILL=30000                                                                       RETURN                                                                          END                                                                       C=====================================================================C         C     SUBROUTINE BITRVC/D PERFORMS BIT REVERSAL REARRANGEMENT OF      C         C     REAL ARRAY OF SIZE OF THE FORM 2**L                             C         C     USAGE: CALL BITRVC(A,L,ILL)                                     C         C          A......1-DIMENSIONAL COMPLEX/DOUBLE ARRAY OF SIZE 2**L     C         C                 INPUT....DATA TO BE REARRANGED                      C         C                 OUTPUT...REARRANGED DATA                            C         C          L......INTEGER INPUT...BASE 2 LOGARITHM OF DATA SIZE       C         C          ILL....INTEGER OUTPUT..ERROR CODE 0: NORMAL TERMINATION    C         C                                            30000: PARAMETER ERROR   C         C     AUTHOR: I.NINOMIYA (CHUBU UNIVERSITY,KASUGAI,AICHI JAPAN 487)   C         C     DATA OF CREATION:  1981-04-01                                   C         C=====================================================================C         C---------------------------------------------------------------------C               SUBROUTINE BITRVC(A,L,ICON)                                               C---------------------------------------------------------------------C               COMPLEX A(*),W                                                                  DIMENSION ITEST(20),INC(20)                                               C---------------------------------------------------------------------C               IF(L.LE.0.OR.L.GT.23) GO TO 8000                                                NN=0                                                                            NR=0                                                                            I=L-1                                                                           M=2**I                                                                          K=2                                                                             IF(I-2) 60,30,10                                                             10 I=I-1                                                                           ITEST(I-1)=M-K                                                                  K=K+K                                                                           INC(I-1)=K-ITEST(I-1)                                                           IF(I-3) 30,10,10                                                          C---------------------------------------------------------------------C            20 NR=INC(I)+NR                                                                 30 MR=M+NR                                                                         IF(NR-NN) 50,50,40                                                           40 W=A(NN+1)                                                                       A(NN+1)=A(NR+1)                                                                 A(NR+1)=W                                                                       MN=M+NN                                                                         W=A(MN+2)                                                                       A(MN+2)=A(MR+2)                                                                 A(MR+2)=W                                                                    50 NN=NN+2                                                                         W=A(NN)                                                                         A(NN)=A(MR+1)                                                                   A(MR+1)=W                                                                       NR=K+NR                                                                      60 MR=M+NR                                                                         IF(NR-NN) 80,80,70                                                           70 W=A(NN+1)                                                                       A(NN+1)=A(NR+1)                                                                 A(NR+1)=W                                                                       MN=M+NN                                                                         W=A(MN+2)                                                                       A(MN+2)=A(MR+2)                                                                 A(MR+2)=W                                                                    80 NN=NN+2                                                                         W=A(NN)                                                                         A(NN)=A(MR+1)                                                                   A(MR+1)=W                                                                       I=1                                                                             IF(NN-M) 100,110,110                                                         90 I=I+1                                                                       100 IF(NR-ITEST(I)) 20,90,90                                                  C---------------------------------------------------------------------C           110 ICON=0                                                                          RETURN                                                                    C---------------------------------------------------------------------C          8000 ICON=30000                                                                      RETURN                                                                          END 	  C=====================================================================C         C     SUBROUTINE FFTR PERFORMS DISCRETE FOURIER ANALYSIS BY           C         C     RADIX-2 REAL FFT ALGORITHM                                      C         C     USAGE: CALL FFTR(A,M,ILL)                                       C         C          A......1-DIMENSIONAL REAL ARRAY OF SIZE 2**M               C         C                 INPUT....DATA TO BE ANALYZED                        C         C                 OUTPUT...ANALYZED DATA                              C         C                          K-TH COSINE COMPONENT IN A(K+1)            C         C                          K-TH SINE COMPONENT IN A(N/2+K+1),N=2**M   C         C          M......INTEGER INPUT...BASE 2 LOGARITHM OF DATA SIZE       C         C          ILL....INTEGER OUTPUT..ERROR CODE 0: NORMAL TERMINATION    C         C                                            30000: PARAMETER ERROR   C         C     SLAVE ROUTINE: BITREV(NUMPAC) FOR BIT REVERSAL REARRANGEMENT    C         C     AUTHOR: I.NINOMIYA (CHUBU UNIVERSITY,KASUGAI,AICHI JAPAN 487)   C         C     DATA OF CREATION:  1981-04-01                                   C         C=====================================================================C         C---------------------------------------------------------------------C               SUBROUTINE FFTR(A,M,ILL)                                                  C---------------------------------------------------------------------C               DIMENSION A(*)                                                                  DOUBLE PRECISION DC(32),DS(32),SS                                         C---------------------------------------------------------------------C         C     DC(I)=COS(PI/2**(I+1)),DS(I)=SIN(PI/2**(I+1))                             C---------------------------------------------------------------------C               DATA DC( 1)/ 0.707106781186547531D+00/                                          DATA DC( 2)/ 0.923879532511286752D+00/                                          DATA DC( 3)/ 0.980785280403230444D+00/                                          DATA DC( 4)/ 0.995184726672196887D+00/                                          DATA DC( 5)/ 0.998795456205172391D+00/                                          DATA DC( 6)/ 0.999698818696204222D+00/                                          DATA DC( 7)/ 0.999924701839144545D+00/                                          DATA DC( 8)/ 0.999981175282601137D+00/                                          DATA DC( 9)/ 0.999995293809576177D+00/                                          DATA DC(10)/ 0.999998823451701907D+00/                                          DATA DC(11)/ 0.999999705862882213D+00/                                          DATA DC(12)/ 0.999999926465717850D+00/                                          DATA DC(13)/ 0.999999981616429293D+00/                                          DATA DC(14)/ 0.999999995404107320D+00/                                          DATA DC(15)/ 0.999999998851026833D+00/                                          DATA DC(16)/ 0.999999999712756701D+00/                                          DATA DC(17)/ 0.999999999928189179D+00/                                          DATA DC(18)/ 0.999999999982047291D+00/                                          DATA DC(19)/ 0.999999999995511826D+00/                                          DATA DC(20)/ 0.999999999998877953D+00/                                          DATA DC(21)/ 0.999999999999719488D+00/                                          DATA DC(22)/ 0.999999999999929876D+00/                                          DATA DC(23)/ 0.999999999999982472D+00/                                          DATA DC(24)/ 0.999999999999995615D+00/                                          DATA DC(25)/ 0.999999999999998904D+00/                                          DATA DC(26)/ 0.999999999999999722D+00/                                          DATA DC(27)/ 0.999999999999999931D+00/                                          DATA DC(28)/ 0.999999999999999986D+00/                                          DATA DC(29)/ 0.100000000000000000D+01/                                          DATA DC(30)/ 0.100000000000000000D+01/                                          DATA DC(31)/ 0.100000000000000000D+01/                                          DATA DC(32)/ 0.100000000000000000D+01/                                          DATA DS( 1)/ 0.707106781186547531D+00/                                          DATA DS( 2)/ 0.382683432365089768D+00/                                          DATA DS( 3)/ 0.195090322016128262D+00/                                          DATA DS( 4)/ 0.980171403295606036D-01/                                          DATA DS( 5)/ 0.490676743274180141D-01/                                          DATA DS( 6)/ 0.245412285229122881D-01/                                          DATA DS( 7)/ 0.122715382857199263D-01/                                          DATA DS( 8)/ 0.613588464915447527D-02/                                          DATA DS( 9)/ 0.306795676296597625D-02/                                          DATA DS(10)/ 0.153398018628476561D-02/                                          DATA DS(11)/ 0.766990318742704540D-03/                                          DATA DS(12)/ 0.383495187571395563D-03/                                          DATA DS(13)/ 0.191747597310703308D-03/                                          DATA DS(14)/ 0.958737990959773447D-04/                                          DATA DS(15)/ 0.479368996030668847D-04/                                          DATA DS(16)/ 0.239684498084182193D-04/                                          DATA DS(17)/ 0.119842249050697064D-04/                                          DATA DS(18)/ 0.599211245264242774D-05/                                          DATA DS(19)/ 0.299605622633466084D-05/                                          DATA DS(20)/ 0.149802811316901114D-05/                                          DATA DS(21)/ 0.749014056584715715D-06/                                          DATA DS(22)/ 0.374507028292384129D-06/                                          DATA DS(23)/ 0.187253514146195347D-06/                                          DATA DS(24)/ 0.936267570730980836D-07/                                          DATA DS(25)/ 0.468133785365490931D-07/                                          DATA DS(26)/ 0.234066892682745532D-07/                                          DATA DS(27)/ 0.117033446341372770D-07/                                          DATA DS(28)/ 0.585167231706863850D-08/                                          DATA DS(29)/ 0.292583615853431935D-08/                                          DATA DS(30)/ 0.146291807926715968D-08/                                          DATA DS(31)/ 0.731459039633579864D-09/                                          DATA DS(32)/ 0.365729519816789906D-09/                                    C---------------------------------------------------------------------C               N2=1                                                                            IF(M.LE.0) GOTO 110                                                             IF(M.EQ.1) GOTO 90                                                        C---------------------------------------------------------------------C               CALL BITREV(A,M,ILL)                                                      C---------------------------------------------------------------------C               N=2**M                                                                          F=2.0/FLOAT(N)                                                                  DO 20 L=1,N,2                                                                   P=A(L+1)                                                                        A(L+1)=(A(L)-P)*F                                                            20 A(L)=(A(L)+P)*F                                                                 N1=1                                                                            N2=2                                                                            N3=4                                                                            N4=8                                                                            DO 70 I=1,M-2                                                                   DO 30 L=1,N,N3                                                                  L1=L+N2                                                                         P=A(L)                                                                          A(L)=P+A(L1)                                                                 30 A(L1)=P-A(L1)                                                                   C=DC(I)                                                                         S=DS(I)                                                                         SS=DS(I)+DS(I)                                                                  CO=1.0                                                                          SO=0.0                                                                          DO 50 K=1,N1-1                                                                  N3K=N3-K                                                                        N2K=N2-K                                                                        DO 40 J=1,N,N4                                                                  L0=J+K                                                                          L2=L0+N3                                                                        L1=J+N3K                                                                        L3=L1+N3                                                                        P=C*A(L2)-S*A(L3)                                                               Q=S*A(L2)+C*A(L3)                                                               A(L2)=Q-A(L1)                                                                   A(L3)=Q+A(L1)                                                                   A(L1)=A(L0)-P                                                                   A(L0)=A(L0)+P                                                                   L1=L0+N2                                                                        L3=L1+N3                                                                        L0=J+N2K                                                                        L2=L0+N3                                                                        P=A(L2)*S-A(L3)*C                                                               Q=A(L2)*C+A(L3)*S                                                               A(L2)=Q-A(L1)                                                                   A(L3)=Q+A(L1)                                                                   A(L1)=A(L0)-P                                                                   A(L0)=A(L0)+P                                                                40 CONTINUE                                                                        CN=CO-SS*S                                                                      SN=SS*C+SO                                                                      CO=C                                                                            C=CN                                                                            SO=S                                                                         50 S=SN                                                                            DO 60 J=1,N,N4                                                                  L0=J+N1                                                                         L2=L0+N3                                                                        L1=L2-N2                                                                        L3=L1+N3                                                                        P=A(L2)*S-A(L3)*C                                                               Q=A(L2)*C+A(L3)*S                                                               A(L2)=Q-A(L1)                                                                   A(L3)=Q+A(L1)                                                                   A(L1)=A(L0)-P                                                                60 A(L0)=A(L0)+P                                                                   N1=N2                                                                           N2=N3                                                                           N3=N4                                                                        70 N4=N4+N4                                                                        DO 80 J=2,N1                                                                    P=A(N2+J)                                                                       A(N2+J)=A(N+2-J)                                                             80 A(N+2-J)=P                                                                   90 A(1)=(A(1)+A(N2+1))*0.5                                                         A(N2+1)=A(1)-A(N2+1)                                                      C---------------------------------------------------------------------C           100 ILL=0                                                                           RETURN                                                                    C---------------------------------------------------------------------C           110 IF(M.EQ.0) GO TO 100                                                            ILL=30000                                                                       RETURN                                                                          END                                                                       C=====================================================================C         C     SUBROUTINE FFTRI PERFORMS DISCRETE FOURIER SYMTHESIS BY         C         C     RADIX-2 REAL FFT ALGORITHM                                      C         C     USAGE: CALL FFTRI(A,M,ILL)                                      C         C          A......1-DIMENSIONAL REAL ARRAY OF SIZE 2**M               C         C                 INPUT....DATA TO BE SYNTHESIZED                     C         C                          K-TH COSINE COMPONENT IN A(K+1)            C         C                          K-TH SINE COMPONENT IN A(N/2+K+1),N=2**M   C         C                 OUTPUT...SYNTHESIZED DATA                           C         C          M......INTEGER INPUT...BASE 2 LOGARITHM OF DATA SIZE       C         C          ILL....INTEGER OUTPUT..ERROR CODE 0: NORMAL TERMINATION    C         C                                            30000: PARAMETER ERROR   C         C     SLAVE ROUTINE: BITREV(NUMPAC) FOR BIT REVERSAL REARRANGEMENT    C         C     AUTHOR: I.NINOMIYA (CHUBU UNIVERSITY,KASUGAI,AICHI JAPAN 487)   C         C     DATA OF CREATION:  1981-04-01                                   C         C=====================================================================C         C---------------------------------------------------------------------C               SUBROUTINE FFTRI(A,M,ILL)                                                 C---------------------------------------------------------------------C               DIMENSION A(*)                                                                  DOUBLE PRECISION DC(32),DS(32),SS                                         C---------------------------------------------------------------------C         C     DC(I)=COS(PI/2**(I+1)),DS(I)=SIN(PI/2**(I+1))                             C---------------------------------------------------------------------C               DATA DC( 1)/ 0.707106781186547531D+00/                                          DATA DC( 2)/ 0.923879532511286752D+00/                                          DATA DC( 3)/ 0.980785280403230444D+00/                                          DATA DC( 4)/ 0.995184726672196887D+00/                                          DATA DC( 5)/ 0.998795456205172391D+00/                                          DATA DC( 6)/ 0.999698818696204222D+00/                                          DATA DC( 7)/ 0.999924701839144545D+00/                                          DATA DC( 8)/ 0.999981175282601137D+00/                                          DATA DC( 9)/ 0.999995293809576177D+00/                                          DATA DC(10)/ 0.999998823451701907D+00/                                          DATA DC(11)/ 0.999999705862882213D+00/                                          DATA DC(12)/ 0.999999926465717850D+00/                                          DATA DC(13)/ 0.999999981616429293D+00/                                          DATA DC(14)/ 0.999999995404107320D+00/                                          DATA DC(15)/ 0.999999998851026833D+00/                                          DATA DC(16)/ 0.999999999712756701D+00/                                          DATA DC(17)/ 0.999999999928189179D+00/                                          DATA DC(18)/ 0.999999999982047291D+00/                                          DATA DC(19)/ 0.999999999995511826D+00/                                          DATA DC(20)/ 0.999999999998877953D+00/                                          DATA DC(21)/ 0.999999999999719488D+00/                                          DATA DC(22)/ 0.999999999999929876D+00/                                          DATA DC(23)/ 0.999999999999982472D+00/                                          DATA DC(24)/ 0.999999999999995615D+00/                                          DATA DC(25)/ 0.999999999999998904D+00/                                          DATA DC(26)/ 0.999999999999999722D+00/                                          DATA DC(27)/ 0.999999999999999931D+00/                                          DATA DC(28)/ 0.999999999999999986D+00/                                          DATA DC(29)/ 0.100000000000000000D+01/                                          DATA DC(30)/ 0.100000000000000000D+01/                                          DATA DC(31)/ 0.100000000000000000D+01/                                          DATA DC(32)/ 0.100000000000000000D+01/                                          DATA DS( 1)/ 0.707106781186547531D+00/                                          DATA DS( 2)/ 0.382683432365089768D+00/                                          DATA DS( 3)/ 0.195090322016128262D+00/                                          DATA DS( 4)/ 0.980171403295606036D-01/                                          DATA DS( 5)/ 0.490676743274180141D-01/                                          DATA DS( 6)/ 0.245412285229122881D-01/                                          DATA DS( 7)/ 0.122715382857199263D-01/                                          DATA DS( 8)/ 0.613588464915447527D-02/                                          DATA DS( 9)/ 0.306795676296597625D-02/                                          DATA DS(10)/ 0.153398018628476561D-02/                                          DATA DS(11)/ 0.766990318742704540D-03/                                          DATA DS(12)/ 0.383495187571395563D-03/                                          DATA DS(13)/ 0.191747597310703308D-03/                                          DATA DS(14)/ 0.958737990959773447D-04/                                          DATA DS(15)/ 0.479368996030668847D-04/                                          DATA DS(16)/ 0.239684498084182193D-04/                                          DATA DS(17)/ 0.119842249050697064D-04/                                          DATA DS(18)/ 0.599211245264242774D-05/                                          DATA DS(19)/ 0.299605622633466084D-05/                                          DATA DS(20)/ 0.149802811316901114D-05/                                          DATA DS(21)/ 0.749014056584715715D-06/                                          DATA DS(22)/ 0.374507028292384129D-06/                                          DATA DS(23)/ 0.187253514146195347D-06/                                          DATA DS(24)/ 0.936267570730980836D-07/                                          DATA DS(25)/ 0.468133785365490931D-07/                                          DATA DS(26)/ 0.234066892682745532D-07/                                          DATA DS(27)/ 0.117033446341372770D-07/                                          DATA DS(28)/ 0.585167231706863850D-08/                                          DATA DS(29)/ 0.292583615853431935D-08/                                          DATA DS(30)/ 0.146291807926715968D-08/                                          DATA DS(31)/ 0.731459039633579864D-09/                                          DATA DS(32)/ 0.365729519816789906D-09/                                    C---------------------------------------------------------------------C               IF(M.LE.0) GO TO 100                                                            N=2**M                                                                          N4=N                                                                            N3=N/2                                                                          N2=N3/2                                                                         N1=N2/2                                                                         P=A(1)                                                                          A(1)=P+A(N3+1)                                                                  A(N3+1)=P-A(N3+1)                                                               IF(M.EQ.1) GOTO 90                                                              DO 20 J=2,N2                                                                    P=A(N3+J)                                                                       A(N3+J)=A(N+2-J)                                                             20 A(N+2-J)=P                                                                      DO 80 I=M-2,0,-1                                                                DO 40 L=1,N,N3                                                                  L1=L+N2                                                                         P=A(L)                                                                          A(L)=P+A(L1)                                                                 40 A(L1)=P-A(L1)                                                                   IF(N1.EQ.0) GO TO 90                                                            C=DC(I)                                                                         S=DS(I)                                                                         SS=DS(I)+DS(I)                                                                  CO=1.0                                                                          SO=0.0                                                                          DO 60 K=1,N1-1                                                                  N3K=N3-K                                                                        N2K=N2-K                                                                        DO 50 J=1,N,N4                                                                  L0=J+K                                                                          L2=L0+N3                                                                        L1=J+N3K                                                                        L3=L1+N3                                                                        P=A(L0)-A(L1)                                                                   Q=A(L2)+A(L3)                                                                   A(L0)=A(L0)+A(L1)                                                               A(L1)=A(L3)-A(L2)                                                               A(L2)=C*P+S*Q                                                                   A(L3)=C*Q-S*P                                                                   L1=L0+N2                                                                        L3=L1+N3                                                                        L0=J+N2K                                                                        L2=L0+N3                                                                        P=A(L0)-A(L1)                                                                   Q=A(L2)+A(L3)                                                                   A(L0)=A(L0)+A(L1)                                                               A(L1)=A(L3)-A(L2)                                                               A(L2)=S*P+C*Q                                                                   A(L3)=S*Q-C*P                                                                50 CONTINUE                                                                        CN=CO-SS*S                                                                      SN=SS*C+SO                                                                      CO=C                                                                            C=CN                                                                            SO=S                                                                         60 S=SN                                                                            DO 70 J=1,N,N4                                                                  L0=J+N1                                                                         L2=L0+N3                                                                        L1=L2-N2                                                                        L3=L1+N3                                                                        P=A(L0)-A(L1)                                                                   Q=A(L2)+A(L3)                                                                   A(L0)=A(L0)+A(L1)                                                               A(L1)=A(L3)-A(L2)                                                               A(L2)=P*S+Q*C                                                                70 A(L3)=Q*S-P*C                                                                   N4=N3                                                                           N3=N2                                                                           N2=N1                                                                        80 N1=N1/2                                                                   C---------------------------------------------------------------------C            90 CALL BITREV(A,M,ILL)                                                      C---------------------------------------------------------------------C               RETURN                                                                    C---------------------------------------------------------------------C           100 IF(M.LT.0) GO TO 110                                                            ILL=0                                                                           RETURN                                                                      110 ILL=30000                                                                       RETURN                                                                          END                                                                       C=====================================================================C         C     SUBROUTINE BITREV PERFORMS BIT REVERSAL REARRANGEMENT OF        C         C     REAL ARRAY OF SIZE OF THE FORM 2**L                             C         C     USAGE: CALL BITREV(A,L,ILL)                                     C         C          A......1-DIMENSIONAL REAL ARRAY OF SIZE 2**L               C         C                 INPUT....DATA TO BE REARRANGED                      C         C                 OUTPUT...REARRANGED DATA                            C         C          L......INTEGER INPUT...BASE 2 LOGARITHM OF DATA SIZE       C         C          ILL....INTEGER OUTPUT..ERROR CODE 0: NORMAL TERMINATION    C         C                                            30000: PARAMETER ERROR   C         C     AUTHOR: I.NINOMIYA (CHUBU UNIVERSITY,KASUGAI,AICHI JAPAN 487)   C         C     DATA OF CREATION:  1981-04-01                                   C         C=====================================================================C         C---------------------------------------------------------------------C               SUBROUTINE BITREV(A,L,ICON)                                               C---------------------------------------------------------------------C               DIMENSION A(*),ITEST(20),INC(20)                                          C-------- PREPARATION ------------------------------------------------C               IF(L.LE.0.OR.L.GT.23) GO TO 8000                                                NN=0                                                                            NR=0                                                                            I=L-1                                                                           M=2**I                                                                          K=2                                                                             IF(I-2) 60,30,10                                                             10 I=I-1                                                                           ITEST(I-1)=M-K                                                                  K=K+K                                                                           INC(I-1)=K-ITEST(I-1)                                                           IF(I-3) 30,10,10                                                          C-------- MAIN LOOP --------------------------------------------------C            20 NR=INC(I)+NR                                                                 30 MR=M+NR                                                                         IF(NR-NN) 50,50,40                                                           40 W=A(NN+1)                                                                       A(NN+1)=A(NR+1)                                                                 A(NR+1)=W                                                                       MN=M+NN                                                                         W=A(MN+2)                                                                       A(MN+2)=A(MR+2)                                                                 A(MR+2)=W                                                                    50 NN=NN+2                                                                         W=A(NN)                                                                         A(NN)=A(MR+1)                                                                   A(MR+1)=W                                                                       NR=K+NR                                                                      60 MR=M+NR                                                                         IF(NR-NN) 80,80,70                                                           70 W=A(NN+1)                                                                       A(NN+1)=A(NR+1)                                                                 A(NR+1)=W                                                                       MN=M+NN                                                                         W=A(MN+2)                                                                       A(MN+2)=A(MR+2)                                                                 A(MR+2)=W                                                                    80 NN=NN+2                                                                         W=A(NN)                                                                         A(NN)=A(MR+1)                                                                   A(MR+1)=W                                                                       I=1                                                                             IF(NN-M) 100,110,110                                                         90 I=I+1                                                                       100 IF(NR-ITEST(I)) 20,90,90                                                  C-------- EXIT -------------------------------------------------------C           110 ICON=0                                                                          RETURN                                                                    C-------- ERROR HANDLING ---------------------------------------------C          8000 ICON=30000                                                                      RETURN                                                                          END                                                                       